 private int dfs(int src, int n) {

 int start = src;

 while (!visited[start]){

 visited[start] = true;

 if (touch[start]){

 return Integer.MAX_VALUE;

 }

 else{

 touch[start] = true;

 }

 start = p[start];

 }

 ArrayList<Integer> cycles = new ArrayList<>();

 cycles.add(start);

