 }

 }

 return Integer.MAX_VALUE;

 }

 private ArrayList<Integer> getDiv(int n){

 ArrayList<Integer> divs = new ArrayList<>();

 for (int d = 1; d * d <= n; d++){

 if (n % d == 0){

 divs.add(d);

 }

 if (d * d != n){

 divs.add(n / d);

 }

 }

 Collections.sort(divs);

 return divs;

 }

