 nodes = []
 self.findTarget(root, target, nodes)
 ans = self.findKChild(nodes[0], k)
 for i in range(1, len(nodes)):
 node = nodes[i]
 if i == k:
 ans.append(node.data)
 break
 if node.right == nodes[i - 1]:
 ans += self.findKChild(node.left, k - i - 1)
 else:
 ans += self.findKChild(node.right, k - i - 1)
 ans.sort()
 return ans

