from collections import deque, defaultdict

def BFS(graph, source, visited):
 n = len(graph)
 queue = deque()
 queue.append(source)
 visited[source] = True
 while len(queue) > 0:
 u = queue.popleft()
 yield u
 for v in graph[u]:
 if not visited[v]:
 visited[v] = True
 queue.append(v)

