 def unite(self, x, y):
 s1 = self.find(x)
 s2 = self.find(y)
 if s1 != s2:
 r1 = self.table[s1]
 r2 = self.table[s2]
 if r1 <= r2:
 self.table[s2] = s1
 if r1 == r2:
 self.table[s1] -= 1
 else:
 self.table[s1] = s2
