string kr(string &s,vector<vector<int>> &dp)

{

   int n=s.size();

   for(int i=0;i<n;i++) dp[i][i]=1;

   for(int i=1;i<n;i++) if(s[i]==s[i-1]) dp[i-1][i]=1;

   for(int k=3;k<=n;k++)

   {

      for(int i=0;i<=n-k;i++)

      {

         int j=i+k-1;

         if(s[i]==s[j] and dp[i+1][j-1]==1) dp[i][j]=1;

      }

   }

   int ans=0,start=-1,end=-1;

   for(int i=0;i<n;i++)

   {

      if(dp[0][i] and ans<(i+1)){

         ans=i+1;

         start=0;

         end=i;

      }

   }

   for(int i=n-1;i>=0;i--)

   {

      if(dp[i][n-1] and ans<(n-i)){

         ans=n-i;

         start=i;

         end=n-1;

      }

   }

   return s.substr(start,end-start+1);

}

string kr1(string &s,vector<vector<int>> &dp)

{

