   while(l<=r and s[l]==s[r])

   {

      if(l==r) p+=s[l];

      else{

         p+=s[l];

         q=s[r]+q;

      }

      l++;

      r--;

   }

   if(l>r) return p+q;

   int ans=0,start=-1,end=-1;

   for(int i=r;i>=l;i--){



      if(dp[i][r]==1 and ans<(r-i+1)){

         ans=(r-i+1);

         start=i;

         end=r;

      }

   }



   for(int i=l;i<=r;i++){

      if(dp[l][i]==1 and ans<(i-l+1)){

         ans=(i-l+1);

         start=l;

         end=i;

      }

   }

   string re=p+s.substr(start,end-start+1)+q;

   return re;

}

