 for (int i = 0; i < w; i++) {
 for (int j = 0; j < h; j++) {
 int curr = grid[j][i];
 int p = prev[j];
 if (curr > p) {
 sideCounter += curr - p;
 }
 prev[j] = curr;
 }
 }

 prev = new int[h];
 for (int i = w - 1; i >= 0; i--) {
 for (int j = 0; j < h; j++) {
 int curr = grid[j][i];
 int p = prev[j];
 if (curr > p) {
 sideCounter += curr - p;
 }
 prev[j] = curr;
 }
 }

 prev = new int[w];
 for (int i = 0; i < h; i++) {
 for (int j = 0; j < w; j++) {
