template<typename Monoid, typename F> struct SegmentTree { int sz; vector<Monoid> v_4_seg; const F f; const Monoid M1; SegmentTree(int n, const F f, const Monoid &M1) : f(f), M1(M1) { sz = 1; while(sz < n) sz <<= 1; v_4_seg.assign(2 * sz, M1); } SegmentTree(const F f, const Monoid &M1) : f(f), M1(M1) {} void resize(int n) { sz = 1; while(sz < n) sz <<= 1; v_4_seg.resize(2 * sz, M1); } void clear() { v_4_seg.clear(); } void set(int k, const Monoid &x) { v_4_seg[k+sz] = x; } void build() { for(int k = sz - 1; k > 0; k--) { v_4_seg[k] = f(v_4_seg[2*k], v_4_seg[2*k+1]); } } void build(const vector<Monoid> &A) { int n = A.size(); resize(n); rep(i, n) set(i, A[i]); build(); } void update(int k, const Monoid &x) { k += sz; v_4_seg[k] = x; while(k >>= 1) { v_4_seg[k] = f(v_4_seg[2*k], v_4_seg[2*k+1]); } } Monoid query(int a, int b) { Monoid L = M1, R = M1; for(a += sz, b += sz; a < b; a >>= 1, b >>= 1) { if(a & 1) L = f(L, v_4_seg[a++]); if(b & 1) R = f(v_4_seg[--b], R); } return f(L, R); } Monoid operator[](const int &k) const { return v_4_seg[k+sz]; } Monoid v_3_all() { return v_4_seg[1]; } void print(int n) { for (int i=0; i<n; i++) { cout << query(i, i+1); if (i == n-1) cout << endl; else cout << ' '; } } template<typename C> int find_subtree(int a, const C &check, Monoid &M, bool type) { while(a < sz) { Monoid nxt = type ? f(v_4_seg[2 * a + type], M) : f(M, v_4_seg[2 * a + type]); if(check(nxt)) a = 2 * a + type; else M = nxt, a = 2 * a + 1 - type; } return a - sz; } template<typename C> int find_first(int a, const C &check) { Monoid L = M1; if(a <= 0) { if(check(f(L, v_4_seg[1]))) return find_subtree(1, check, L, false); return -1; } int b = sz; for(a += sz, b += sz; a < b; a >>= 1, b >>= 1) { if(a & 1) { Monoid nxt = f(L, v_4_seg[a]); if(check(nxt)) return find_subtree(a, check, L, false); L = nxt; ++a; } } return -1; } template<typename C> int find_last(int b, const C &check) { Monoid R = M1; if(b >= sz) { if(check(f(v_4_seg[1], R))) return find_subtree(1, check, R,