class Solution {
public:
 int maxLength(vector<string>& arr) {
 int result = 0;
 vector<pair<int, int>> counters;
 counters.reserve(arr.size());
 for (int i = 0; i != arr.size(); ++i) {
 int c = count(arr[i]);
 if (c != -1) {
 counters.emplace_back(i, c);
 }
 };
 return search(arr, counters, 0, 0);
 }
 int search(vector<string>& arr, const vector<pair<int, int>>& counters, int index, int mask) {
 if (index == counters.size()) {
 return 0;
 }
 if (dp.find(index) != dp.end() && dp[index].find(mask) != dp[index].end()) {
 return dp[index][mask];
 }
 dp[index][mask] = search(arr, counters, index + 1, mask);
 if ((counters[index].second & mask) == 0) {
 dp[index][mask] = max(dp[index][mask], static_cast<int>(arr[counters[index].first].size()) + search(arr, counters, index + 1, mask | counters[index].second));
 }
 return dp[index][mask];
 }

 int count(const string& s) {
 int result = 0;
 for (char c : s) {
 if (result & (1 << (c - 'a'))) {
 return -1;
 }
 result |= 1 << (c - 'a');
 }
 return result;
 }
private:
 unordered_map<int, unordered_map<int, int>> dp;
};

class Solution:
    def removeAlmostEqualCharacters(self, word: str) -> int:
        """
        This function takes a string `word` and returns the minimum number of deletions
        needed to make the string contain only characters that are at most one character away
        from their neighbors in the alphabet.

        Args:
            word: The string to be processed.

        Returns:
            The minimum number of deletions needed.
        """


        n = len(word)
        dp = [[float('inf')] * 26 for _ in range(n + 1)]  
        dp[0] = [0] * 26  


        for i in range(1, n + 1):
            c = ord(word[i - 1]) - ord('a')  
            for a in range(26):  
                for b in range(26):  
                    if abs(a - b) > 1:  
                        dp[i][a] = min(dp[i][a], dp[i - 1][b] + (a != c))


        return min(dp[n])

