public class Solution70 {
    final static int M = 20;
    public static void main (String [] args) throws IOException {

        final BufferedReader input = new BufferedReader(new InputStreamReader(System.in));
        PrintWriter out = new PrintWriter(System.out);

        int n = Integer.parseInt(input.readLine());
        int[] ns = readArrayInt(n, input);
        out.println(calc(ns, n));
        out.close();       
    }

    private static long calc(final int[] ns, final int n) {
        int[] rd = new int[M];
        for (int a : ns){
            for (int i=0;i<M;++i){
                if ((a & (1<<i)) != 0){
                    rd[i]++;
                }
            }
        }
        long res = 0;
        for (int i=0;i<n;++i){
            long a = 0;
            for (int j=0;j<M;++j){
                if (rd[j]>0){
                    a += 1 << j;
                    rd[j]--;
                }
            }
            res += a * a;
        }
        return res;
    }

    private static void printArray(long[] ns, final PrintWriter out){
        for (int i=0;i<ns.length;++i){
            out.print(ns[i]);
            if (i+1<ns.length)out.print(" ");
            else out.println();
        }
    }

