class Solution { 
public:
 int numBusesToDestination(vector<vector<int>>& routes, int S, int T) {

 if (S == T) return 0;

 vector< unordered_set<int> > buses; 
 for (int i = 0; i < routes.size(); ++i)
 {
 unordered_set<int> temp;
 for (int t = 0; t < routes[i].size(); ++t)
 temp.insert( routes[i][t] );
 buses.push_back( temp );
 }

 int n = buses.size();
 if (n == 0) return 0;

 vector< vector<int> > nexts(n);
 for (int i = 0; i < buses.size(); ++i)
 for (int t = i + 1; t < buses.size(); ++t)
 { 
 if (Intersect(buses[i], buses[t]) == true) 
 {
 nexts[i].push_back(t);
 nexts[t].push_back(i);
 }
 }

 deque< pair<int,int> > queue; 
 vector<int> checked(n, 0);
 for (int i = 0; i < buses.size(); ++i)
 {
 if ( buses[i].find(S) != buses[i].end() )
 {
 queue.push_back( {i, 1} );
 checked[i] = 1;
 if ( buses[i].find(T) != buses[i].end() ) return 1; 
 }
 }

 while (queue.size() > 0)
 {
 pair<int, int> cur = queue.front();
 queue.pop_front();
 int busIndex = cur.first;

 for (int t = 0; t < nexts[busIndex].size(); ++t)
 {
 int nextIndex = nexts[busIndex][t];

 if (checked[ nextIndex ] == 1) continue;
 if (buses[nextIndex].find(T) != buses[nextIndex].end()) return cur.second + 1;

 queue.push_back( {nextIndex, cur.second + 1} );
 checked[nextIndex] = 1;
 }
 }

 return -1;
 }

 bool Intersect(unordered_set<int>& a, unordered_set<int>& b)
 { 
 if (a.size() < b.size())
 {
 for (auto item : a)
 {
 if (b.find(item) != b.end()) return true;
 }
 }
 else
 {
 for (auto item : b)
 {
 if (a.find(item) != a.end()) return true;
 }
 }

 return false;
 }
};

