class Solution {
public:
 int findTheCity(int n, vector<vector<int>>& edges, int dis) {
 unordered_map<int, unordered_map<int, int>> path;
 map<int, set<int>> res;
 for(auto v : edges) {
 path[v[0]][v[1]] = v[2];
 path[v[1]][v[0]] = v[2];
 }
 for(int i = 0; i < n; i++) {
 unordered_map<int, int> nei;
 nei[i] = dis;
 dfs(i, path, dis, nei);
 res[nei.size()].insert(i);
 }
 /*
 for(auto p : res) {
 for(auto n : p.second) {
 cout << p.first << " " << n << " | ";
 }
 }
 */
 return *(res.begin()->second.rbegin());
 }
 void dfs(int cur, unordered_map<int, unordered_map<int, int>> &path, int &dis, unordered_map<int, int> &nei) {
 if(dis < 0 || (nei.count(cur) && nei[cur] > dis))
 return;
 nei[cur] = dis;
 for(auto n : path[cur]) {
 dis -= n.second;
 dfs(n.first, path, dis, nei);
 dis += n.second;
 }
 }
};

