using namespace std;

typedef long long ll;

int mod = 1e9+7;

class DSNode{

 public:

 int rank, data;

 DSNode* parent;

};

class DisjointSet{

 private:

 map<int, DSNode*> hash;

 DSNode* findParent(DSNode* node){

 if(node == node->parent) return node;

 node->parent = findParent(node->parent);

 return node->parent;

 }

 public:

 void initialize(int data){

 DSNode* node = new DSNode();

 node->data = data;

 node->rank = 0;

 node->parent = node;

 hash[data] = node;

 }

 void UNION(int data1, int data2){

 DSNode* node1 = findParent(hash[data1]);

 DSNode* node2 = findParent(hash[data2]);

 if(node1->data == node2->data) return;

 if(node1->rank >= node2->rank){

 if(node1->rank == node2->rank)

 node1->rank++;

 node2->parent = node1;

 }else node1->parent = node2;

 }

 int findParent(int data){

 return findParent(hash[data])->data;

 }

};

int power(int n){

 if(n == 1) return 2;

 ll ans = power(n/2);

 ans = (ans*ans)%mod;

 return n&1 ? (ans*2)%mod : ans;

}

int numAns(int* a1, int* a2, int n){

 DisjointSet DS;

 for(int i=1 ; i<=n ; i++) DS.initialize(i);

 for(int i=0 ; i<n ; i++)

 DS.UNION(a1[i], a2[i]);

 set<int> ans;

 for(int i=1 ; i<n ; i++)

 ans.insert(DS.findParent(i));

 return ans.size();

}

