public:
 int mergeStones(vector<int>& stones, int K) {
 unordered_map<int, int> mem;
 int min_cost = merge(stones, 0, stones.size() - 1, 1, K, mem);
 return min_cost;
 }

 int merge(vector<int>& stones, int start, int end, int k, int K, unordered_map<int, int>& mem) {
 int hash = (((start * 31) + end) * 31 + k);
 if (mem.find(hash) != mem.end()) {
 return mem[hash];
 }

 int len = end - start + 1;
 if (k == 0 || k > len) {
 return -1;
 }

 if (k == 1 && k == len) {
 return 0;
 }

 int sep = k;
 if (k == 1) {
 sep = K;
 }
 int min_cost = -1;
 for (int i = 1; i < sep; ++i) {
 for (int j = start; j < end; ++j) {
 int left_cost = merge(stones, start, j, i, K, mem);
 int right_cost = merge(stones, j + 1, end, sep - i, K, mem);

 if (left_cost != -1 && right_cost != -1) {
 int cost = left_cost + right_cost;
 if (min_cost == -1) {
 min_cost = cost;
 } else {
 min_cost = min(min_cost, cost);
 }
 }
 }
 }

 if (k == 1 && min_cost != -1) {
 int total = 0;
 for (int i = start; i <= end; ++i) {
 total += stones[i];
 }
 min_cost += total;
 }

 mem[hash] = min_cost;
 return min_cost;
 }
};

